import { buildMatchFn } from "../../_lib/buildMatchFn.js";
import { buildMatchPatternFn } from "../../_lib/buildMatchPatternFn.js";

const matchOrdinalNumberPattern = /^(\d+)(-?пД┘Ё)?/i;
const parseOrdinalNumberPattern = /\d+/i;

const matchEraPatterns = {
  narrow: /^(┘ѓ|пе)/i,
  abbreviated: /^(┘ѓ\.?\s?┘Є\.?|пе\.?\s?┘Є\.?|┘Є\.?)/i,
  wide: /^(┘ѓпе┘ё пДп▓ ┘Єпгп▒пф|┘Єпгп▒█ї п┤┘Ёп│█ї|пеп╣п» пДп▓ ┘Єпгп▒пф)/i,
};
const parseEraPatterns = {
  any: [/^┘ѓпе┘ё/i, /^пеп╣п»/i],
};

const matchQuarterPatterns = {
  narrow: /^[1234]/i,

  abbreviated: /^(┘Ђ|Q|п│Рђї┘Ё)[1234]/i,
  wide: /^(┘Ђпх┘ё|quarter|п│┘ЄРђї┘ЁпД┘Є┘Є) [1234](-пД┘Ё|пД┘Ё)?/i,
};
const parseQuarterPatterns = {
  any: [/1/i, /2/i, /3/i, /4/i],
};

const matchMonthPatterns = {
  narrow: /^(┘Ђп▒|пДп▒|п«п▒|пф█ї|┘Ёп▒|п┤┘Є|┘Ё┘Є|пбпе|пбп░|п»█ї|пе┘Є|пДп│)/i,
  abbreviated: /^(┘Ђп▒┘ѕ|пДп▒п»|п«п▒п»|пф█їп▒|┘Ёп▒п»|п┤┘Єп▒|┘Ё┘Єп▒|пбпепД|пбп░п▒|п»█ї|пе┘Є┘Ё|пДп│┘Ђ)/i,
  wide: /^(┘Ђп▒┘ѕп▒п»█ї┘є|пДп▒п»█їпе┘Єп┤пф|п«п▒п»пДп»|пф█їп▒|┘Ёп▒п»пДп»|п┤┘Єп▒█ї┘ѕп▒|┘Ё┘Єп▒|пбпепД┘є|пбп░п▒|п»█ї|пе┘Є┘Ё┘є|пДп│┘Ђ┘єп»)/i,
};
const parseMonthPatterns = {
  narrow: [
    /^┘Ђп▒/i,
    /^пДп▒/i,
    /^п«п▒/i,
    /^пф█ї/i,
    /^┘Ёп▒/i,
    /^п┤┘Є/i,
    /^┘Ё┘Є/i,
    /^пбпе/i,
    /^пбп░/i,
    /^п»█ї/i,
    /^пе┘Є/i,
    /^пДп│/i,
  ],

  any: [
    /^┘Ђп▒/i,
    /^пДп▒/i,
    /^п«п▒/i,
    /^пф█ї/i,
    /^┘Ёп▒/i,
    /^п┤┘Є/i,
    /^┘Ё┘Є/i,
    /^пбпе/i,
    /^пбп░/i,
    /^п»█ї/i,
    /^пе┘Є/i,
    /^пДп│/i,
  ],
};

const matchDayPatterns = {
  narrow: /^[п┤█їп»п│┌є┘Йпг]/i,
  short: /^(п┤|пг|1п┤|2п┤|3п┤|4п┤|5п┤)/i,
  abbreviated: /^(█ї┌Еп┤┘єпе┘Є|п»┘ѕп┤┘єпе┘Є|п│┘ЄРђїп┤┘єпе┘Є|┌є┘ЄпДп▒п┤┘єпе┘Є|┘Й┘єпгРђїп┤┘єпе┘Є|пг┘Ёп╣┘Є|п┤┘єпе┘Є)/i,
  wide: /^(█ї┌Еп┤┘єпе┘Є|п»┘ѕп┤┘єпе┘Є|п│┘ЄРђїп┤┘єпе┘Є|┌є┘ЄпДп▒п┤┘єпе┘Є|┘Й┘єпгРђїп┤┘єпе┘Є|пг┘Ёп╣┘Є|п┤┘єпе┘Є)/i,
};
const parseDayPatterns = {
  narrow: [/^█ї/i, /^п»┘ѕ/i, /^п│/i, /^┌є/i, /^┘Й/i, /^пг/i, /^п┤/i],
  any: [
    /^(█ї|1п┤|█ї┌Еп┤┘єпе┘Є)/i,
    /^(п»|2п┤|п»┘ѕп┤┘єпе┘Є)/i,
    /^(п│|3п┤|п│┘ЄРђїп┤┘єпе┘Є)/i,
    /^(┌є|4п┤|┌є┘ЄпДп▒п┤┘єпе┘Є)/i,
    /^(┘Й|5п┤|┘Й┘єпгп┤┘єпе┘Є)/i,
    /^(пг|пг┘Ёп╣┘Є)/i,
    /^(п┤|п┤┘єпе┘Є)/i,
  ],
};

const matchDayPeriodPatterns = {
  narrow: /^(пе|┘ѓ|┘є|пИ|пх|пе.пИ.|п╣|п┤)/i,
  any: /^(┘ѓ.пИ.|пе.пИ.|┘ѓпе┘ёРђїпДп▓пИ┘Єп▒|┘є█ї┘Ё┘ЄРђїп┤пе|пИ┘Єп▒|пхпепГ|пеп╣п»пДп▓пИ┘Єп▒|п╣пхп▒|п┤пе)/i,
};
const parseDayPeriodPatterns = {
  any: {
    am: /^(┘ѓ|┘ѓ.пИ.|┘ѓпе┘ёРђїпДп▓пИ┘Єп▒)/i,
    pm: /^(пе|пе.пИ.|пеп╣п»пДп▓пИ┘Єп▒)/i,
    midnight: /^(Рђї┘є█ї┘Ё┘ЄРђїп┤пе|┘є)/i,
    noon: /^(пИ|пИ┘Єп▒)/i,
    morning: /^(пх|пхпепГ)/i,
    afternoon: /^(пе|пе.пИ.|пеп╣п»пДп▓пИ┘Єп▒)/i,
    evening: /^(п╣|п╣пхп▒)/i,
    night: /^(п┤|п┤пе)/i,
  },
};

export const match = {
  ordinalNumber: buildMatchPatternFn({
    matchPattern: matchOrdinalNumberPattern,
    parsePattern: parseOrdinalNumberPattern,
    valueCallback: (value) => parseInt(value, 10),
  }),

  era: buildMatchFn({
    matchPatterns: matchEraPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseEraPatterns,
    defaultParseWidth: "any",
  }),

  quarter: buildMatchFn({
    matchPatterns: matchQuarterPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseQuarterPatterns,
    defaultParseWidth: "any",
    valueCallback: (index) => index + 1,
  }),

  month: buildMatchFn({
    matchPatterns: matchMonthPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseMonthPatterns,
    defaultParseWidth: "any",
  }),

  day: buildMatchFn({
    matchPatterns: matchDayPatterns,
    defaultMatchWidth: "wide",
    parsePatterns: parseDayPatterns,
    defaultParseWidth: "any",
  }),

  dayPeriod: buildMatchFn({
    matchPatterns: matchDayPeriodPatterns,
    defaultMatchWidth: "any",
    parsePatterns: parseDayPeriodPatterns,
    defaultParseWidth: "any",
  }),
};
