/**
 * UIManager - ├ЎРђд├Ў╦є├ў┬ф├Ў╦є├ў┬▒ ├ЎРђд├ў┬»├Џ┼њ├ў┬▒├Џ┼њ├ў┬ф ├Ў┬Й├Џ┼њ├ў┬Д├ЎРђд ├Ў╦є ├ў┬«├ў┬и├ў┬Д
 * ├ў┬г├ў┬Д├Џ┼њ├џ┬»├ў┬▓├Џ┼њ├ЎРђа alert() ├ў┬е├ў┬Д Toast Notifications ├ЎРђд├ў┬»├ў┬▒├ЎРђа
 */
class UIManager {
    constructor() {
        // ├ў┬Д├Џ┼њ├ў┬г├ў┬Д├ў┬» ├џ┬Е├ў┬Д├ЎРђа├ў┬ф├Џ┼њ├ЎРђа├ў┬▒ ├ў┬е├ў┬▒├ў┬Д├Џ┼њ ├Ў┬Й├Џ┼њ├ў┬Д├ЎРђд├бРѓг┼њ├ЎРђА├ў┬Д ├ў┬Д├џ┬»├ў┬▒ ├Ў╦є├ў┬г├Ў╦є├ў┬» ├ЎРђа├ў┬»├ў┬Д├ў┬▒├ў┬»
        if (!document.getElementById('toast-container')) {
            this.container = document.createElement('div');
            this.container.id = 'toast-container';
            document.body.appendChild(this.container);
        } else {
            this.container = document.getElementById('toast-container');
        }
    }

    showToast(message, type = 'info') {
        const toast = document.createElement('div');
        toast.className = `toast ${type}`;
        
        let icon = 'info';
        if (type === 'success') icon = 'check_circle';
        if (type === 'error') icon = 'error';
        if (type === 'warning') icon = 'warning_amber';

        const iconEl = document.createElement('span');
        iconEl.className = 'material-icons-round toast-icon';
        iconEl.textContent = icon;

        const messageEl = document.createElement('span');
        messageEl.style.flex = '1';
        messageEl.textContent = String(message ?? '');

        const closeEl = document.createElement('span');
        closeEl.className = 'material-icons-round';
        closeEl.style.cursor = 'pointer';
        closeEl.style.fontSize = '18px';
        closeEl.style.opacity = '0.6';
        closeEl.textContent = 'close';
        closeEl.addEventListener('click', () => toast.remove());

        toast.appendChild(iconEl);
        toast.appendChild(messageEl);
        toast.appendChild(closeEl);

        this.container.appendChild(toast);

        // ├ў┬Г├ў┬░├Ў┬Ђ ├ў┬«├Ў╦є├ў┬»├џ┬Е├ў┬Д├ў┬▒ ├ў┬е├ў┬╣├ў┬» ├ў┬Д├ў┬▓ 5 ├ў┬Ф├ў┬Д├ЎРђа├Џ┼њ├ЎРђА
        setTimeout(() => {
            if (toast.parentElement) {
                toast.classList.add('hide');
                toast.addEventListener('animationend', () => toast.remove());
            }
        }, 5000);
    }

    success(msg) { this.showToast(msg, 'success'); }
    error(msg) { this.showToast(msg, 'error'); }
    warning(msg) { this.showToast(msg, 'warning'); }
    info(msg) { this.showToast(msg, 'info'); }

    // ├ЎРђд├ў┬»├Џ┼њ├ў┬▒├Џ┼њ├ў┬ф ├Ў╦є├ў┬Х├ў┬╣├Џ┼њ├ў┬ф ├ў┬»├џ┬Е├ЎРђд├ЎРђА├бРѓг┼њ├ЎРђА├ў┬Д (Loading)
    setBtnLoading(btn, status) {
        if (!btn) return;
        if (status) {
            btn.classList.add('loading');
            btn.dataset.originalText = btn.innerText;
        } else {
            btn.classList.remove('loading');
        }
    }
}

// ├ў┬Д├Џ┼њ├ў┬г├ў┬Д├ў┬» ├Џ┼њ├џ┬Е ├ЎРђа├ЎРђд├Ў╦є├ЎРђа├ЎРђА ├џ┬»├ЎРђъ├Ў╦є├ў┬е├ў┬Д├ЎРђъ
const UI = new UIManager();
window.UI = UI;

// ├ЎРђд├Џ┼њ├ў┬Д├ЎРђа├ў┬е├ў┬▒├ЎРђА├ў┬Д├Џ┼њ ├џ┬»├ЎРђъ├Ў╦є├ў┬е├ў┬Д├ЎРђъ ├ў┬е├ў┬▒├ў┬Д├Џ┼њ ├ў┬Д├ў┬│├ў┬ф├Ў┬Ђ├ў┬Д├ў┬»├ЎРђА ├ў┬│├ў┬▒├Џ┼њ├ў┬╣
window.showToast = (msg, type) => UI.showToast(msg, type);
window.showSuccess = (msg) => UI.success(msg);
window.showError = (msg) => UI.error(msg);
window.showInfo = (msg) => UI.info(msg);
window.showWarning = (msg) => UI.warning(msg);
