        // ├ЎРђд├ЎРђа├ў┬и├ЎРђџ ├ў┬»├ў┬│├џ┬Е├ў┬ф├ў┬Д├Ў┬Й (├ў┬Д├ў┬│├ў┬ф├Ў┬Ђ├ў┬Д├ў┬»├ЎРђА ├ў┬Д├ў┬▓ ├џ┬Е├ЎРђъ├ў┬Д├ў┬│ ├ў┬▒├Ў╦є├Џ┼њ body ├ў┬е├ў┬▒├ў┬Д├Џ┼њ ├ў┬г├ў┬Д├ў┬е├ў┬г├ў┬Д├Џ┼њ├Џ┼њ ├ЎРђд├ў┬Г├ў┬ф├Ў╦є├ў┬Д)
        document.body.classList.toggle('sidebar-closed');
        
        // ├ў┬░├ў┬«├Џ┼њ├ў┬▒├ЎРђА ├Ў╦є├ў┬Х├ў┬╣├Џ┼њ├ў┬ф ├ў┬»├ў┬▒ ├џ┬Е├Ў╦є├џ┬Е├Џ┼њ ├ў┬е├ў┬▒├ў┬Д├Џ┼њ ├ў┬▒├Ў┬Ђ├ў┬▒├ў┬┤ ├ў┬е├ў┬╣├ў┬»├Џ┼њ
        const isClosed = document.body.classList.contains('sidebar-closed');
        document.cookie = `sidebar_status=${isClosed ? 'closed' : 'open'}; path=/; max-age=31536000`;
