//  6. CONTEXT MENU (├ЎРђд├ЎРђа├Ў╦є├Џ┼њ ├ў┬▒├ў┬Д├ў┬│├ў┬ф ├џ┬Е├ЎРђъ├Џ┼њ├џ┬Е)
// ============================================================

function handleAction(action) {
    if (!SELECTED_DOC_ID) {
        showToast('├ЎРђъ├ў┬и├Ў┬Ђ├ў┬Д├ЎРђ╣ ├ў┬Д├ў┬е├ў┬ф├ў┬»├ў┬Д ├Џ┼њ├џ┬Е ├ў┬│├ЎРђа├ў┬» ├ў┬▒├ў┬Д ├ў┬Д├ЎРђа├ў┬ф├ў┬«├ў┬Д├ў┬е ├џ┬Е├ЎРђа├Џ┼њ├ў┬»', 'error');
        return;
    }
    
    switch(action) {
        case 'view':
            showToast(`├ЎРђд├ў┬┤├ў┬Д├ЎРђА├ў┬»├ЎРђА ├ў┬г├ў┬▓├ў┬д├Џ┼њ├ў┬Д├ў┬ф ├ў┬│├ЎРђа├ў┬» ${SELECTED_DOC_ID}`, 'info');
            break;
        case 'history':
            showToast(`├ў┬ф├ў┬Д├ў┬▒├Џ┼њ├ў┬«├џРђа├ЎРђА ├ў┬│├ЎРђа├ў┬» ${SELECTED_DOC_ID}`, 'info');
            break;
        case 'upload':
            showToast(`├ў┬б├Ў┬Й├ЎРђъ├Ў╦є├ў┬» ├Ў┬Ђ├ў┬Д├Џ┼њ├ЎРђъ ├ў┬г├ў┬»├Џ┼њ├ў┬» ├ў┬е├ў┬▒├ў┬Д├Џ┼њ ├ў┬│├ЎРђа├ў┬» ${SELECTED_DOC_ID}`, 'info');
            break;
        case 'delete':
            if (confirm(`├ў┬б├Џ┼њ├ў┬Д ├ў┬Д├ў┬▓ ├ў┬Г├ў┬░├Ў┬Ђ ├ў┬│├ЎРђа├ў┬» ${SELECTED_DOC_ID} ├ў┬Д├ў┬и├ЎРђд├Џ┼њ├ЎРђа├ў┬Д├ЎРђа ├ў┬»├ў┬Д├ў┬▒├Џ┼њ├ў┬»├ў┼И`)) {
                showToast(`├ў┬│├ЎРђа├ў┬» ${SELECTED_DOC_ID} ├ў┬Г├ў┬░├Ў┬Ђ ├ў┬┤├ў┬»`, 'success');
            }
            break;
    }
    
    // ├ў┬е├ў┬│├ў┬ф├ЎРђа ├ЎРђд├ЎРђа├Ў╦є├Џ┼њ ├ў┬▒├ў┬Д├ў┬│├ў┬ф ├џ┬Е├ЎРђъ├Џ┼њ├џ┬Е
    const ctxMenu = document.getElementById('context-menu');
    if (ctxMenu) ctxMenu.classList.remove('show');
}

