function copyToClipboard(text) {
    navigator.clipboard.writeText(text).then(() => {
        showToast('├џ┬Е├Ў┬Й├Џ┼њ ├ў┬┤├ў┬»', 'success', 1500);
    }).catch(() => {
        showToast('├ў┬«├ў┬и├ў┬Д ├ў┬»├ў┬▒ ├џ┬Е├Ў┬Й├Џ┼њ', 'error');
    });
}

// ============================================================
//  8. ANIMATIONS (├ў┬Д├ЎРђа├Џ┼њ├ЎРђд├Џ┼њ├ў┬┤├ЎРђа├бРѓг┼њ├ЎРђА├ў┬Д)
// ============================================================

// ├ў┬Д├ў┬Х├ў┬Д├Ў┬Ђ├ЎРђА ├џ┬Е├ў┬▒├ў┬»├ЎРђа ├ў┬Д├ў┬│├ў┬ф├ў┬Д├Џ┼њ├ЎРђъ ├ў┬Д├ЎРђа├Џ┼њ├ЎРђд├Џ┼њ├ў┬┤├ЎРђа├бРѓг┼њ├ЎРђА├ў┬Д ├ў┬Д├џ┬»├ў┬▒ ├Ў╦є├ў┬г├Ў╦є├ў┬» ├ЎРђа├ў┬»├ў┬Д├ў┬▒├ў┬»
if (!document.querySelector('#toast-animations')) {
    const style = document.createElement('style');
    style.id = 'toast-animations';
    style.textContent = `
        @keyframes slideIn {
            from { transform: translateX(100%); opacity: 0; }
            to { transform: translateX(0); opacity: 1; }
        }
        @keyframes slideOut {
            from { transform: translateX(0); opacity: 1; }
            to { transform: translateX(100%); opacity: 0; }
        }
    `;
    document.head.appendChild(style);
}



